INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Block Editor (Gutenberg)$q$, $q$A drag-and-drop, block-based editor for building posts and pages without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Full Site Editing$q$, $q$Customize headers, footers, templates, and global styles using block themes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Plugin Ecosystem$q$, $q$Tens of thousands of free and premium plugins add SEO, e-commerce, forms, security, and more.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Theme System$q$, $q$Thousands of free and paid themes control the design and layout of a site.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$User Roles and Permissions$q$, $q$Built-in roles (administrator, editor, author, contributor, subscriber) control access.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$REST API$q$, $q$A native REST API enables headless WordPress setups and integration with external apps.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Multisite Networks$q$, $q$Run and manage multiple related sites from a single WordPress installation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Media Library$q$, $q$Centralized management of images, video, and other uploaded files.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Custom Post Types and Taxonomies$q$, $q$Model structured content beyond blog posts, such as portfolios, products, or listings.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Multilingual Support$q$, $q$Core and plugin-based tools support translating and localizing site content and the admin interface.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Core software is free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Enormous plugin and theme ecosystem covers nearly any feature need$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Large community, documentation, and developer talent pool make support easy to find$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Highly flexible, from simple blogs to complex e-commerce and membership sites$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Full control over hosting, data, and customization since it is self-hosted$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Requires choosing and managing your own hosting, unlike fully hosted builders$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Security and performance depend heavily on keeping core, themes, and plugins updated$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Quality varies widely depending on chosen theme, plugins, and hosting provider$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Can become slow or bloated if too many plugins are installed$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Steeper learning curve than simplified website builders for complete beginners$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Is WordPress really free?$q$, $q$Yes, the core WordPress software from WordPress.org is free and open source under the GPL. You still pay separately for hosting, a domain name, and any premium themes or plugins you choose to use.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$What is the difference between WordPress.org and WordPress.com?$q$, $q$WordPress.org distributes the free, self-hosted software that you install on your own hosting, giving full control. WordPress.com is a separate, hosted service built on that same software but with a managed hosting plan and different pricing tiers.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Do I need coding skills to use WordPress?$q$, $q$No. Many people build and manage WordPress sites using the block editor, themes, and plugins without writing code. Coding knowledge (PHP, HTML, CSS, JavaScript) becomes useful for deeper customization.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Can WordPress be used for e-commerce?$q$, $q$Yes. With plugins like WooCommerce, WordPress can power full online stores, including product catalogs, payments, shipping, and inventory management.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Is WordPress secure?$q$, $q$WordPress core is actively maintained and patched, but overall site security depends on keeping core, themes, and plugins updated, using trusted extensions, and following good hosting and password practices.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Blogging and Publishing$q$, $q$Write, organize, and publish articles with categories, tags, comments, and revision history.$q$, $q$Bloggers, writers, and content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Business and Marketing Websites$q$, $q$Build a professional site with pages, contact forms, and SEO plugins to represent a company online.$q$, $q$Small businesses and freelancers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Online Stores$q$, $q$Add WooCommerce or another e-commerce plugin to sell physical or digital products directly from a WordPress site.$q$, $q$Retailers and independent sellers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Agency and Client Sites$q$, $q$Build and maintain multiple custom client websites using WordPress's theme and plugin flexibility.$q$, $q$Web design and development agencies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$WordPress Core Software$q$, $q$Free$q$, $q$N/A$q$, $q$["Open-source GPL license","Block editor and full site editing","Access to official theme and plugin directories","Self-hosted, full control over code and data"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$Self-Hosted (typical costs)$q$, $q$Varies by host and extensions$q$, $q$Monthly or annual$q$, $q$["Web hosting purchased separately","Domain name registration","Optional premium themes and plugins","Optional developer or agency support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$WordPress is a free, open-source content management system (CMS) that anyone can download, install, and run on their own web server. First released in 2003 by Matt Mullenweg and Mike Little as a fork of the b2/cafelog blogging tool, it has grown into the software behind a substantial share of all websites on the internet, spanning personal blogs, news outlets, corporate sites, portfolios, and online stores.$q$, $q$Unlike the hosted WordPress.com service, self-hosted WordPress (from WordPress.org) gives site owners full control: they choose their own hosting provider, install the core software, and extend it with thousands of themes and plugins. The core software is licensed under the GPL, meaning it is free to use, modify, and redistribute, with development steered by a large volunteer community and coordinated through the WordPress Foundation.$q$, $q$At its heart, WordPress combines a PHP and MySQL/MariaDB-based architecture with a block-based editor (Gutenberg) for building pages and posts. Its plugin and theme ecosystem allows the same core installation to become almost anything, from a simple blog to a complex membership site or e-commerce store via extensions like WooCommerce.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$who-wordpress-is-for$q$, $q$Who WordPress Is For$q$, 2, ARRAY[$q$WordPress suits bloggers, small business owners, freelancers, agencies, and developers who want a flexible publishing platform without being locked into a single vendor's hosting or pricing structure. Because the software is free and the plugin ecosystem is enormous, it appeals to anyone building a website on a limited budget who still wants professional features.$q$, $q$Developers and agencies favor WordPress because of its maturity, extensive documentation, and large talent pool; it is easy to find WordPress developers, designers, and support resources compared to niche or proprietary platforms. Content-heavy publishers and news organizations also rely on it for its strong editorial workflow and taxonomy features.$q$, $q$It also works well for non-technical users who want to self-host: with managed WordPress hosting providers handling server maintenance, updates, and backups, a beginner can run a self-hosted WordPress site without deep technical knowledge, while still retaining more control than a fully hosted website builder.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Users who want a fully managed, zero-maintenance experience with nothing to configure may find self-hosted WordPress more responsibility than they want, since it requires choosing hosting, installing updates, and managing security yourself (or via a managed host). Those users may be better served by WordPress.com or a closed website builder like Squarespace or Wix.$q$, $q$Teams building highly custom web applications, rather than content-driven websites, may find WordPress's content-first architecture and plugin-based extensibility awkward compared to a framework built for their specific use case. Similarly, developers who want a strict headless-first, API-only architecture without legacy PHP conventions may prefer a modern headless CMS instead.$q$, $q$Site owners who are uncomfortable with ongoing maintenance duties, such as applying core, theme, and plugin updates and monitoring for security vulnerabilities, can run into trouble, since a poorly maintained WordPress site is a common target for attacks. Anyone unwilling to invest at least some time or budget into hosting, security, and updates should weigh that cost carefully.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$WordPress ships with the block-based Gutenberg editor for building posts and pages visually, full site editing for customizing headers, footers, and templates through block themes, and a built-in media library for managing images and files. Core also includes user role management, comments, revisions, and a REST API for headless or app-driven use cases.$q$, $q$Its real power comes from extensibility: tens of thousands of free and paid plugins add functionality like SEO optimization, e-commerce (WooCommerce), forms, caching, security, backups, and membership systems, while thousands of themes control design and layout. Multisite support lets a single installation run a network of related sites.$q$, $q$WordPress also supports multilingual content, custom post types and taxonomies for structured content, and a plugin/theme update mechanism from the admin dashboard. Its open architecture means features can be added or removed as needed, rather than being fixed by the platform vendor.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', $q$the-wordpress-experience$q$, $q$The WordPress Experience$q$, 2, ARRAY[$q$Working in WordPress typically starts with choosing a hosting provider (shared, managed, or cloud) and installing the software, often via one-click installers. From there, the wp-admin dashboard is the control center for writing content, managing plugins and themes, and configuring settings, with the block editor providing a drag-and-drop-like experience for laying out pages.$q$, $q$Because WordPress is so widely used, the community experience is a major part of using it: extensive official documentation, forums, WordCamp events, and a huge base of tutorials, agencies, and freelance developers make it easy to find help or hire support. This ecosystem maturity is often cited as a key advantage over newer or more proprietary platforms.$q$, $q$The tradeoff is that the experience can vary widely depending on the quality of the hosting, theme, and plugins chosen; a well-configured WordPress site can be fast, secure, and easy to manage, while a poorly configured one (too many plugins, cheap hosting, no maintenance plan) can feel slow or fragile. Much of the perceived quality of WordPress comes down to how it is set up and maintained rather than the core software itself.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8741e733-7b13-489c-8696-9d50fbf35b42', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$AI Rewrite$q$, $q$Generates multiple alternative phrasings for a highlighted sentence, letting users adjust wording while preserving the original meaning.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Tone Adjustment$q$, $q$Shifts a sentence between casual and formal registers with a single click, useful for tailoring messages to different audiences.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Spices (Facts, Examples, Counterarguments)$q$, $q$Inserts relevant supporting facts, examples, analogies, or counterarguments into a draft to strengthen or expand an argument.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$AI Summarizer$q$, $q$Condenses long articles, documents, or video transcripts into concise summaries to speed up reading and research.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Grammar and Spelling Correction$q$, $q$Continuously checks text as it is typed and flags spelling and grammar issues alongside rewrite suggestions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Browser Extension$q$, $q$Overlays Wordtune's rewrite panel across Gmail, Google Docs, LinkedIn, and most text fields in Chrome, Edge, and Firefox.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$iOS Writing Keyboard$q$, $q$Brings rewrite and correction capabilities to a custom keyboard usable inside any iOS app, including messaging and social apps.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Sentence Shortening and Expansion$q$, $q$Rewrites a sentence to fit a shorter or longer target length without losing its core meaning.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Translate with Rewrite$q$, $q$Accepts input in several non-English languages and produces English-language rewrite suggestions in a single step.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Rewrite suggestions go beyond grammar fixes to genuinely improve clarity and tone$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Simple, low-friction interface that requires almost no onboarding$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Works across the web via a browser extension rather than being locked to one app$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Free plan is usable for occasional rewriting needs before requiring payment$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Summarizer and Spices features add value beyond basic paraphrasing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Free plan's daily rewrite limit is restrictive for frequent writers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Output is English-only, limiting usefulness for multilingual writing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Suggestions can feel repetitive or generic on longer or technical passages$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$No Android app and no current standalone Mac desktop app$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Premium pricing can feel high relative to the scope of features offered$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$What does Wordtune actually do?$q$, $q$Wordtune is an AI writing assistant that suggests alternative phrasings for sentences you highlight, helping you adjust tone, clarity, and length while keeping your original meaning.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Is Wordtune free to use?$q$, $q$Yes, Wordtune offers a free plan with a limited number of daily rewrites and monthly summaries, alongside paid Advanced and Unlimited plans for higher usage.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Does Wordtune support languages other than English?$q$, $q$Wordtune can accept input in several languages and translate it, but its rewrite and generation output is produced in English only.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Where can I use Wordtune?$q$, $q$Wordtune is available as a web app, a browser extension for Chrome, Edge, and Firefox, and an iOS app with a custom writing keyboard.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$How is Wordtune different from Grammarly?$q$, $q$Grammarly focuses primarily on correctness and grammar checking, while Wordtune emphasizes rewriting and rephrasing to improve how an idea is expressed, though both tools include some overlapping correction features.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Polishing professional emails$q$, $q$Rewrite draft emails to sound clearer, more concise, or more appropriately formal before sending them to clients or colleagues.$q$, $q$Business professionals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Improving academic and essay writing$q$, $q$Paraphrase source material and rephrase sentences to improve flow and readability in assignments and papers.$q$, $q$Students and non-native English speakers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Drafting consistent marketing copy$q$, $q$Generate multiple tone variations of the same message for different social media channels or campaigns.$q$, $q$Content marketers and social media managers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Summarizing long documents and videos$q$, $q$Condense lengthy articles, reports, or YouTube video transcripts into quick digests to save reading time.$q$, $q$Researchers and knowledge workers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Basic$q$, $q$$0$q$, $q$Free$q$, $q$["10 rewrites and AI suggestions per day","3 AI summarizations per month","Unlimited spelling corrections","Unlimited grammar checks"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Advanced$q$, $q$$6.99/month ($4.89/month billed annually)$q$, $q$Monthly or annual$q$, $q$["30 rewrites and AI suggestions per day","15 AI summarizations per month","Unlimited AI recommendations","Unlimited spelling and grammar checks","3-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$Unlimited$q$, $q$$9.99/month ($6.99/month billed annually)$q$, $q$Monthly or annual$q$, $q$["Unlimited rewrites and AI suggestions","Unlimited AI summarizations","Vocabulary, clarity, and fluency enhancements","Premium support","3-day free trial"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Wordtune is an AI-powered writing assistant developed by AI21 Labs, an Israeli natural language processing company. Rather than simply flagging grammar mistakes, Wordtune focuses on rewriting: it suggests alternative phrasings for a sentence or paragraph so users can communicate more clearly, adjust tone, or fit a word count, while keeping the original meaning intact.$q$, $q$The product is built on large language models developed in-house at AI21 Labs and is delivered through a web app, a browser extension for Chrome, Edge, and Firefox, and an iOS keyboard app. Its core interaction pattern is simple: highlight text, click Rewrite, and choose from a set of AI-generated alternatives, with options to shift formality, shorten, expand, or add supporting content.$q$, $q$Wordtune positions itself as a companion to, rather than a replacement for, traditional grammar checkers. Where tools like Grammarly emphasize correctness, Wordtune emphasizes expression, helping writers who know what they want to say but struggle to say it well, quickly, or in the right tone for a given audience.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$who-wordtune-is-for$q$, $q$Who Wordtune Is For$q$, 2, ARRAY[$q$Wordtune is well suited to professionals who write emails, reports, and client-facing documents regularly and want a faster way to polish tone and clarity without hiring an editor. Its rewrite suggestions are especially useful for softening or formalizing messages before they go out.$q$, $q$Non-native English speakers and students are another core audience, using Wordtune to check that a sentence reads naturally, expand a thin paragraph, or paraphrase source material for essays and assignments. The tool's Spices feature, which inserts facts, examples, or counterarguments, can help writers develop underdeveloped points.$q$, $q$Content marketers, social media managers, and small teams that need a consistent, professional voice across many short pieces of writing also benefit, since Wordtune can quickly generate several tone variations of the same message for different channels or audiences.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Writers who need to produce content in languages other than English should look elsewhere: Wordtune can accept input in several languages for translation purposes, but its rewrite and generation output is English-only, so it cannot serve as a native multilingual writing assistant.$q$, $q$High-volume users who rewrite dozens of sentences a day will quickly outgrow the free plan's daily rewrite cap, and even the paid tiers are scoped around personal or small-team writing rather than bulk, programmatic content production.$q$, $q$Teams looking for a full long-form content generation platform, SEO drafting engine, or an API to embed rewriting into their own product are also a poor fit, since Wordtune is a consumer-facing rewriting tool rather than a developer platform or enterprise content suite.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The centerpiece feature is Rewrite, which generates multiple phrasing alternatives for a selected sentence, letting users pick a version that is more casual, more formal, shorter, or longer. Spices extends this by inserting relevant facts, examples, analogies, or counterarguments directly into a draft to strengthen an argument.$q$, $q$Wordtune also includes an AI summarizer that condenses long articles, documents, or even YouTube video transcripts into shorter digests, along with built-in spelling and grammar correction that runs continuously as users type, similar to a standard grammar checker.$q$, $q$On the distribution side, the browser extension overlays Wordtune's rewrite panel on top of Gmail, Google Docs, LinkedIn, and most text fields across the web, while the iOS app brings the same rewriting capability to a custom keyboard for use inside any mobile app.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', $q$the-wordtune-experience$q$, $q$The Wordtune Experience$q$, 2, ARRAY[$q$Day to day, Wordtune feels lightweight: there is little onboarding required, and its side-panel interface for rewrites is intuitive enough that most users are productive within minutes of installing the extension. Suggestions typically appear within a second or two of clicking Rewrite.$q$, $q$The quality of suggestions is generally strong for shorter sentences and common business writing, though some users report that alternatives can feel repetitive or generic on longer or more technical passages, requiring manual editing rather than a one-click fix.$q$, $q$The free plan is usable but capped tightly enough that regular users are nudged toward a paid tier fairly quickly, and some reviewers consider the premium pricing steep relative to the scope of what the tool does compared with broader AI writing suites.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
