INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a5fa585a-6104-495a-a452-912fb307c35f', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Multi-board job posting$q$, $q$Publish an opening once and distribute it to a large network of free and premium job boards with a single click, rather than posting to each site individually.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$AI-powered candidate sourcing$q$, $q$An AI sourcing tool searches a large pool of candidate profiles from job boards, social platforms, and Workable's own database to surface passive candidates matching a role.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$AI recruiting agent$q$, $q$An AI agent can help screen, qualify, and engage candidates automatically, reducing manual effort in the early stages of the hiring funnel.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Visual candidate pipeline$q$, $q$Track every applicant through customizable pipeline stages, with the full hiring team able to see status, notes, and next steps in one shared view.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Structured interview kits and scorecards$q$, $q$Build consistent interview guides and scorecards so interviewers evaluate candidates against the same criteria and feedback stays comparable across the panel.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Interview scheduling$q$, $q$Coordinate interviewer availability and let candidates self-schedule interview slots, reducing the back-and-forth of manual calendar coordination.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Offer letters and e-signatures$q$, $q$Generate offer letters from templates and collect e-signatures from candidates directly inside the platform to close out the hiring process.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$HRIS: onboarding, time off, and payroll prep$q$, $q$Beyond hiring, manage new-hire onboarding, employee time-off requests, and payroll preparation from the same system used for recruiting.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Reporting and analytics$q$, $q$Dashboards surface hiring metrics such as time to hire, pipeline conversion, and source effectiveness to help teams track recruiting performance.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Mobile recruiting app$q$, $q$Native iOS and Android apps let hiring managers review resumes, message candidates, and schedule interviews from a phone while away from a desk.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Fast to set up and easy for hiring managers to learn without extensive training$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$AI-powered sourcing draws on a large pool of candidate profiles to help fill roles faster$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$One-click distribution to a large network of job boards from a single dashboard$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Open API and integrations allow connections to other recruiting and HR tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Combines applicant tracking with onboarding and other HR functionality in one platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Pricing scales with company headcount, which can get expensive for larger organizations$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Removal of a lower-cost entry tier has raised the price of entry for small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Reporting and analytics customization is more limited than some competitors offer$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Permission and notification controls are less granular than some teams need$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Add-ons such as video interviewing and texting can push the effective monthly cost above the base plan price$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$What is Workable used for?$q$, $q$Workable is used as an applicant tracking system and hiring platform, letting teams post jobs to multiple boards, source and screen candidates with AI assistance, schedule interviews, and manage offers, with additional HR features like onboarding and time-off tracking on higher plans.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Does Workable offer a free trial?$q$, $q$Yes. Workable offers a 15-day free trial with access to the Standard plan's feature set, and no credit card is required to start.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$How much does Workable cost?$q$, $q$Workable is sold on subscription plans that scale with company headcount, starting at $299 per month for the Standard plan when billed annually, with Premier and Enterprise tiers priced higher for additional features like video interviewing, texting, and priority support.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Does Workable have AI recruiting features?$q$, $q$Yes. Workable includes AI-powered candidate sourcing that searches a large pool of profiles, automated resume screening and candidate scoring, and an AI recruiting agent that can help qualify and engage applicants.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Is Workable a good fit for small businesses?$q$, $q$Workable works well for small and mid-sized businesses that hire on an ongoing basis, though the removal of a lower-cost entry tier means very small companies or infrequent hirers should compare the current plan pricing carefully against their hiring volume before signing up.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Multi-channel job distribution$q$, $q$Post a single job opening to dozens of free and premium job boards at once to maximize applicant reach without manually managing each listing.$q$, $q$Small and mid-sized business recruiters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$AI-assisted candidate sourcing$q$, $q$Use AI sourcing to search a large pool of candidate profiles and proactively reach out to passive candidates for hard-to-fill or specialized roles.$q$, $q$Talent acquisition teams with limited sourcing resources$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Collaborative structured hiring$q$, $q$Coordinate hiring managers and interviewers around shared candidate pipelines, structured interview kits, and standardized scorecards.$q$, $q$Cross-functional hiring teams and hiring managers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Combined recruiting and onboarding$q$, $q$Move new hires directly from an accepted offer into onboarding, time-off tracking, and payroll preparation within the same platform.$q$, $q$Scaling startups and growing HR teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Standard$q$, $q$$299/month$q$, $q$Billed annually (monthly billing also available at a higher rate)$q$, $q$["Unlimited active job postings","One-click posting to a large network of job boards","AI-assisted sourcing and candidate scoring","Structured interview kits and scorecards","Core HRIS: onboarding, time off, and payroll prep","5 language options for candidate-facing content"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Premier$q$, $q$$599/month$q$, $q$Billed annually$q$, $q$["Everything in Standard","Video interviewing included","SMS/texting with candidates included","Candidate assessments included","Performance and engagement tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$Enterprise$q$, $q$$719/month$q$, $q$Billed annually$q$, $q$["Everything in Premier","Single sign-on (SSO) support","Priority support and assistance","Advanced administrative controls"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Workable is a cloud-based applicant tracking system and hiring platform originally launched in 2012 in Athens, Greece, and now headquartered in Boston, Massachusetts. It was built to replace the spreadsheets, shared inboxes, and disconnected tools that many growing companies used to manage recruiting, consolidating job posting, candidate tracking, and interview coordination into a single dashboard.$q$, $q$Over the years Workable has expanded well beyond a pure applicant tracking system. The platform now bundles AI-assisted candidate sourcing, an AI recruiting agent that can screen and qualify applicants, and a growing set of HR information system features such as onboarding, time-off management, and payroll preparation. The goal is to give small and mid-sized organizations a single system for the full employee lifecycle rather than a patchwork of point solutions.$q$, $q$Workable is used by tens of thousands of companies across a wide range of industries and countries, from early-stage startups to established mid-market businesses. Its core pitch centers on speed and simplicity: publish an opening to dozens of job boards at once, let AI help surface and rank qualified candidates, and move people through a structured pipeline with the whole hiring team collaborating in one place.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$who-workable-is-for$q$, $q$Who Workable Is For$q$, 2, ARRAY[$q$Workable is best suited to small and mid-sized businesses that hire regularly but do not have the internal resources to run a fully custom, enterprise-grade recruiting stack. Companies filling anywhere from a handful to a few dozen roles at a time tend to get the most value, since the platform is priced and designed around steady, ongoing hiring rather than occasional one-off recruitment.$q$, $q$It is a strong fit for lean HR and talent teams that want one login for posting jobs, screening applicants, scheduling interviews, and collecting feedback, instead of juggling separate tools for each step. Organizations that value broad, low-effort distribution to dozens of free and paid job boards, along with AI-assisted sourcing to widen the top of the funnel, will find Workable's feature set closely matches their day-to-day workflow.$q$, $q$Workable also suits companies that want room to grow into more HR functionality without switching systems, since onboarding, time off, and light payroll preparation now sit alongside the core recruiting suite. Scaling startups, agencies with moderate and predictable hiring volume, and SMBs that want a modern, easy-to-train-on interface for hiring managers are typical strong-fit users.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Workable is less well suited to very large enterprises with complex, multi-country compliance requirements, elaborate approval chains, or deeply customized workflows, since its configuration options are geared toward simplicity rather than heavy customization. Organizations that need granular, role-based permissions or intricate internal-notification logic may find the system's controls too limited for their governance needs.$q$, $q$High-volume recruiters and staffing agencies that regularly hire for many roles simultaneously should look closely at the pricing model before committing, since Workable's plans scale with company headcount and monthly costs can climb quickly once hiring activity is heavy or a starter-level entry point is no longer offered. Very small companies or those hiring only occasionally may also find the cost of entry harder to justify relative to lighter-weight or free alternatives.$q$, $q$Teams that depend heavily on deep, out-of-the-box integrations with a specific existing HR or finance stack, or that need highly customizable reporting and analytics, may run into friction, since some reviewers note reporting flexibility and third-party integration depth lag behind a few competitors. In those cases it's worth validating Workable's open API and available connectors against specific requirements before switching.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Workable offers one-click posting to a large network of free and premium job boards, a visual candidate pipeline, structured interview kits and scorecards, self-scheduling links for interviews, and templated offer letters with e-signature support. These pieces form the backbone of the day-to-day recruiting workflow for hiring managers and recruiters working together on shared requisitions.$q$, $q$On top of the core ATS, Workable layers AI capabilities: an AI-powered sourcing tool that searches a large pool of candidate profiles to surface passive candidates matching a role, automated resume screening and candidate scoring, and an AI recruiting agent that can handle parts of initial candidate qualification. These tools are aimed at reducing the manual effort of building a shortlist for each open role.$q$, $q$Beyond hiring, Workable's higher tiers add HR information system functionality, including employee onboarding, time-off tracking, and payroll preparation, plus reporting dashboards, a mobile app for iOS and Android, and an open API for connecting to other HR, payroll, or background-check systems used elsewhere in the organization's stack.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', $q$the-workable-experience$q$, $q$The Workable Experience$q$, 2, ARRAY[$q$Day to day, Workable is generally described as clean, modern, and quick to learn, with hiring managers able to review candidates, leave feedback, and move people through the pipeline without much training. Job requisitions, candidate profiles, and interview feedback all live in the same view, which reviewers frequently point to as a reason collaboration between recruiters and hiring managers feels smoother than with more fragmented tools.$q$, $q$The mobile app extends that experience beyond the desktop, letting hiring managers screen resumes, message candidates, and schedule interviews from a phone, which is useful for teams that need to keep hiring moving while away from a computer. The AI sourcing and screening features are typically the most-cited differentiator in user feedback, since they can meaningfully cut down the time spent manually searching for qualified applicants.$q$, $q$The most common friction points raised by users relate to cost as hiring volume grows, since pricing is tied to company headcount and add-ons like video interviewing or texting can push the effective monthly bill above the advertised base price. Some users also note that report customization and fine-grained permission controls are less flexible than they would like, though most describe these as manageable trade-offs given the platform's overall ease of use.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('63552ca4-8785-47c6-9aaf-f0643adf97b5', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
