INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bec0d6fd-87d3-42f0-99a3-c8210c0e6b88', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Interactive Gantt Charts$q$, $q$Visual project timelines with dependencies, critical-path highlighting, and automatic rescheduling when linked tasks shift.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Resource Management$q$, $q$Workload views and capacity charts that show how work is distributed across people and teams so managers can rebalance assignments.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Custom Workflows & Request Forms$q$, $q$Configurable statuses and intake forms that standardize how work is requested, routed, and approved across departments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Proofing & Approvals$q$, $q$Markup and version comparison for documents, images, and video, with structured sign-off steps for creative and content review.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Dashboards & Reporting$q$, $q$Shareable, real-time dashboards and customizable reports that surface project status without manual status meetings.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Automation & AI Features$q$, $q$Rule-based automation plus AI-assisted tools for drafting project plans, summarizing comments, and handling routine updates.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Multiple Work Views$q$, $q$The same projects can be viewed as Gantt charts, Kanban boards, tables, or calendars depending on team preference.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Time Tracking$q$, $q$Built-in timers and timesheets for logging work against tasks and projects for billing or utilization reporting.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Open API & Integrations$q$, $q$An open API plus native integrations with tools such as Salesforce, Microsoft Teams, Slack, Adobe Creative Cloud, and Google Drive.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Enterprise Security & Admin Controls$q$, $q$Granular permissions, SSO, and compliance features aimed at IT and security teams managing access at scale.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Powerful Gantt charts with dependency management and critical-path scheduling$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Flexible enough to support marketing, IT, operations, and creative workflows in one account$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Strong proofing and approval tools for reviewing creative assets$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Extensive integration ecosystem plus an open API$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Scales from small teams to large, governance-heavy enterprises$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Steeper learning curve than simpler task-management tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Pricing escalates quickly once teams move past the Team plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Interface can feel dense or cluttered, especially when first getting configured$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Many of the most useful features are gated behind the Business tier or higher$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Business-tier and above plans require annual billing with seat minimums$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Does Wrike have a free plan?$q$, $q$Yes. Wrike offers a free plan for up to 5 users with basic task management, board views, and table views, though most advanced features require a paid plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$What is the difference between Wrike's Team and Business plans?$q$, $q$The Team plan adds Gantt charts and basic AI features on top of the free tier, while the Business plan unlocks custom workflows, request forms, proofing and approvals, resource management, and deeper integrations.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Does Wrike offer AI features?$q$, $q$Yes. Wrike includes AI-assisted capabilities such as project plan generation, comment summarization, and content editing, with usage scaling up on higher-priced plans.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Can Wrike replace tools like Asana or Jira?$q$, $q$Wrike can replace general project-management tools like Asana for most teams and covers many Agile use cases, though teams with deep engineering-specific workflows may still prefer a dedicated tool like Jira.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$What integrations does Wrike support?$q$, $q$Wrike offers native integrations with tools such as Salesforce, Microsoft Teams, Slack, Adobe Creative Cloud, Google Drive, and Dropbox, along with an open API and connections through platforms like Zapier.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Marketing Campaign Management$q$, $q$Plan campaigns, manage creative requests, and route assets through proofing and approval before publication.$q$, $q$Marketing and creative teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Portfolio & PMO Oversight$q$, $q$Track multiple projects across departments in one system with standardized intake, dashboards, and reporting for leadership.$q$, $q$PMOs and operations leaders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Product & IT Delivery$q$, $q$Combine Gantt-based planning with Kanban boards to manage sprints, releases, and cross-team dependencies.$q$, $q$IT and product teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Professional Services Delivery$q$, $q$Manage client engagements, resourcing, and budgets across concurrent projects with capacity and financial tracking tools.$q$, $q$Professional services and agencies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Up to 5 users","Web, desktop, and mobile apps","Task and project management","Board (Kanban) and table views"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Team$q$, $q$$10/user/month$q$, $q$Annual$q$, $q$["2-15 users","Interactive Gantt charts","AI Essentials (onboarding, content editing, comment summaries)","Shareable dashboards"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Business$q$, $q$$25/user/month$q$, $q$Annual$q$, $q$["5-200 users","Custom workflows and request forms","Proofing and approvals","Resource management","Starter AI Elite features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$Pinnacle / Apex$q$, $q$Custom pricing$q$, $q$Annual (contact sales)$q$, $q$["Advanced resource and capacity planning","Financial budgeting and tracking","Advanced reporting and BI capabilities","Expanded AI Elite usage and Wrike Integrate/Sync"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Wrike is a cloud-based work and project management platform founded in 2006 by Andrew Filev, originally built to give distributed teams a single system for planning, tracking, and collaborating on work. Over nearly two decades it grew from a lightweight task tracker into an enterprise-grade platform used by marketing, creative, IT, and operations teams to manage complex portfolios of projects.$q$, $q$The company has changed ownership several times: Citrix acquired Wrike in 2021 and folded it into what became Cloud Software Group, then spun it out as an independent company in 2022 before Symphony Technology Group (STG) took over ownership in 2023. Throughout these transitions Wrike has kept its core identity as a flexible, highly configurable work management hub rather than a single-purpose tool.$q$, $q$Today Wrike positions itself against competitors like Asana, Monday.com, and Smartsheet, differentiating with deep Gantt chart scheduling, granular permissions, proofing and approval workflows, and an expanding set of AI-assisted features layered onto its existing automation and reporting engine.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$who-wrike-is-for$q$, $q$Who Wrike Is For$q$, 2, ARRAY[$q$Wrike is built for mid-market and enterprise organizations that manage many simultaneous projects across departments and need one system to standardize how work is requested, planned, and tracked. Marketing and creative teams are a particularly strong fit thanks to built-in proofing and approval tools for reviewing creative assets.$q$, $q$IT, product, and professional-services teams also gravitate toward Wrike because it can flex between traditional Gantt-based planning and Agile or Kanban views inside the same account, letting different departments work the way they prefer while leadership still gets a portfolio-level view.$q$, $q$Organizations with dedicated PMO or operations staff who can own workflow design, custom fields, and governance tend to get the most value, since Wrike rewards upfront configuration with strong dashboards, resource management, and reporting later on.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Freelancers, very small teams, or anyone who just needs a simple to-do list will likely find Wrike more tool than they need. The free plan is capped at 5 users with basic task and board views, and much of what makes Wrike distinctive lives behind the paid Business tier and above.$q$, $q$Budget-sensitive teams should also be cautious: Business-tier pricing requires annual billing and a minimum seat count, so per-user costs and total contract value can climb quickly compared with lighter competitors.$q$, $q$Teams that want something they can roll out with zero training may struggle, too. Wrike's flexibility comes with a denser interface and more setup decisions, such as spaces, folders, and custom workflows, than simpler task managers, so organizations unwilling to invest in onboarding may not stick with it.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Wrike's scheduling core includes interactive Gantt charts with dependencies, critical-path awareness, and automatic rescheduling, alongside Kanban boards, table views, and calendars so teams can visualize the same work in different formats.$q$, $q$Resource management tools show workload across people and teams, while custom request forms, configurable workflows, and cross-tagging let admins standardize intake and reporting across departments. Built-in proofing and approval tools support markup and sign-off directly on documents, images, and video.$q$, $q$Higher tiers add advanced reporting and BI-style dashboards, budgeting and financial tracking, and AI features for tasks like generating project plans, summarizing comments, and automating routine updates, on top of an open API and hundreds of native integrations with tools like Salesforce, Adobe Creative Cloud, Microsoft Teams, and Slack.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', $q$the-wrike-experience$q$, $q$The Wrike Experience$q$, 2, ARRAY[$q$New users generally describe a learning curve: Wrike's structure of spaces, folders, projects, and tasks is more layered than flatter tools, and unlocking its best capabilities, like custom workflows, dashboards, and automation, takes deliberate setup rather than working out of the box.$q$, $q$Once configured, day-to-day use benefits from web, desktop, and mobile apps, real-time collaboration, and dashboards that surface status without digging through individual tasks. Reviewers consistently call out the Gantt charts and reporting as high points of the experience.$q$, $q$The tradeoff is density: some users find the interface cluttered and navigation between views slower than with lighter competitors, and several of the most-wanted capabilities are reserved for the Business plan or above, so the practical experience depends heavily on which tier a team is on.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
