INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4a5fa48-12d7-422f-9252-b7bea83b9ff4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Palmyra LLM family$q$, $q$Proprietary large language models built and trained by Writer, including general-purpose and domain-specific variants for creative, vision, and tool-calling tasks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Knowledge Graph$q$, $q$A graph-based retrieval layer that grounds agents and generated content in an organization's own documents, wikis, and business data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$WRITER Agent$q$, $q$A chat-based assistant for drafting, editing, and answering questions using company knowledge and Writer's models.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$AI Studio$q$, $q$A development environment for building, testing, and deploying custom AI agents and applications on top of Writer's models.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Playbooks$q$, $q$No-code, multi-step automations that chain prompts, approvals, and data connectors into repeatable business workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Brand and style governance$q$, $q$Configurable style guides, terminology rules, and content policies to enforce consistent brand voice across large teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Enterprise connectors$q$, $q$Integrations with common business systems and document repositories to feed the Knowledge Graph and agents with live company data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Compliance and security controls$q$, $q$SAML SSO, SCIM provisioning, role-based access control, audit logging, and support for SOC 2 Type II and HIPAA requirements.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Content safety and PII protection$q$, $q$Built-in policies to detect and restrict sensitive or non-compliant content generated by agents and users.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Owns its own Palmyra models rather than reselling third-party APIs, giving more control over data handling and fine-tuning$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Strong compliance posture (SOC 2 Type II, HIPAA support, SSO/SCIM) suited to regulated industries$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Knowledge Graph grounds agents in proprietary company data rather than generic web knowledge$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$No-code Playbooks let non-technical teams automate multi-step content and workflow processes$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Centralized brand and terminology governance helps keep output consistent across large organizations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Full platform capability and pricing are gated behind custom Enterprise sales contracts$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Entry-level Starter plan has limited Playbooks, connectors, and Knowledge Graph storage$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$No perpetually free tier, making it costly for individuals, freelancers, or very small teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$User interface is English-only, even though content generation supports many languages$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Steeper setup and onboarding compared to lightweight, self-serve AI writing tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$What is Writer used for?$q$, $q$Writer is an enterprise generative AI platform used to draft and govern branded content, build custom AI agents, and automate multi-step workflows using company-specific data via its Knowledge Graph.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Does Writer have a free trial?$q$, $q$Yes, Writer offers a 14-day free trial of its Starter plan with no credit card required, though full Enterprise features require a sales-negotiated contract.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$What are Palmyra models?$q$, $q$Palmyra is Writer's proprietary family of large language models, including general-purpose and domain-specific variants, built and hosted by Writer rather than licensed from a third-party model provider.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Is Writer suitable for small businesses or individuals?$q$, $q$Writer is primarily designed for mid-size to large enterprises; its pricing and governance features make it less cost-effective for solo users or very small teams compared with lightweight writing tools.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Does Writer support languages other than English?$q$, $q$Writer's Palmyra models can generate and translate content in more than 30 languages, but the product's own user interface and navigation are only available in English.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Enterprise content and marketing production$q$, $q$Marketing and communications teams use Writer to draft on-brand copy, campaign briefs, and product content at scale while enforcing consistent terminology and style guidelines.$q$, $q$Enterprise marketing and content teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Regulated-industry compliance and knowledge assistance$q$, $q$Financial services, insurance, and healthcare organizations use Writer's Knowledge Graph and compliance controls to build agents that answer questions grounded in policy documents while meeting HIPAA and SOC 2 requirements.$q$, $q$Compliance-sensitive regulated industries$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Internal knowledge agents$q$, $q$IT and platform teams connect internal wikis, CRM data, and document repositories to Writer's Knowledge Graph so employees can query trusted company information through a governed chat interface.$q$, $q$IT and knowledge management teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Workflow automation with Playbooks$q$, $q$Operations teams use no-code Playbooks to chain prompts, approvals, and connectors into repeatable processes such as report generation, claims summarization, or research synthesis.$q$, $q$Operations and business process teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Starter$q$, $q$$29-$39 per user/month$q$, $q$Monthly or annual (annual billing discounted)$q$, $q$["WRITER Agent chat assistant","Up to 5 Playbooks","Up to 3 scheduled routines","One Knowledge Graph with 1 GB storage","Up to 3 active connectors","14-day free trial, no credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Annual contract$q$, $q$["Unlimited Pro seats plus unlimited free Lite (run-only) seats","Unlimited Playbooks and connectors","Full Knowledge Graph with 50 GB storage","Domain-specific Palmyra model tuning","SAML SSO, SCIM, audit logs, and role-based access control","HIPAA BAA and SOC 2 Type II compliance support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Writer is an enterprise generative AI company founded in 2020 by May Habib and Waseem AlShikh and headquartered in San Francisco. What began as an AI writing and brand-compliance tool for marketing teams has grown into a full-stack "agentic" platform: Writer builds its own family of large language models, called Palmyra, and pairs them with a graph-based Knowledge Graph for retrieval over enterprise data, plus an application layer of chat assistants, prebuilt agent "Skills," and no-code "Playbooks" for automating multi-step business processes.$q$, $q$The company has raised roughly $320 million in venture funding, including a $200 million Series C in late 2024 at a $1.9 billion valuation, from investors such as ICONIQ Growth, Premji Invest, Radical Ventures, Salesforce Ventures, and Citi Ventures. Writer positions itself less as a single-purpose writing assistant and more as an end-to-end enterprise AI stack вЂ” model, data layer, and agent orchestration вЂ” aimed at large organizations that want to build and govern their own AI applications rather than rely solely on general-purpose chatbots.$q$, $q$Customers span financial services, healthcare, retail, and technology, with named users including Accenture, Intuit, L'OrГ©al, Uber, Vanguard, and Marriott. Writer's differentiation rests on owning its own models (so customer data isn't sent to third-party model providers by default), strict compliance certifications like SOC 2 Type II and HIPAA support, and tooling for enforcing brand voice, terminology, and content policy at scale across thousands of users.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$who-writer-is-for$q$, $q$Who Writer Is For$q$, 2, ARRAY[$q$Writer is built for mid-size to large enterprises вЂ” particularly marketing, communications, product, and content operations teams вЂ” that need to produce high volumes of on-brand copy while enforcing consistent style, terminology, and compliance rules across many contributors. Organizations in regulated industries such as financial services, insurance, and healthcare are a strong fit because of Writer's compliance posture (HIPAA business associate agreements, SOC 2 Type II, SAML SSO, SCIM, and audit logging).$q$, $q$It also suits enterprises that want to build custom internal AI agents and knowledge assistants rather than string together separate point solutions. Teams with existing knowledge bases, CRM data, or document repositories can use Writer's Knowledge Graph and connectors to ground agents in proprietary company data, making it attractive to IT and platform teams tasked with standing up a governed, company-wide generative AI layer rather than just a writing tool for individuals.$q$, $q$Procurement and security stakeholders who need a vendor willing to sign enterprise contracts, provide dedicated support, and demonstrate model provenance (since Writer trains and controls its own Palmyra models) will also find Writer's positioning appealing compared with reselling access to third-party foundation models.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo creators, freelancers, students, and very small teams are unlikely to be a good fit. Writer's pricing starts at tens of dollars per user per month for a limited agentic tier, with full enterprise capability gated behind custom sales-negotiated contracts вЂ” a cost structure built for organizational budgets rather than individual consumers, and there's no perpetually free tier for casual use.$q$, $q$Businesses just looking for a simple grammar checker or a lightweight ChatGPT-style writing helper may find Writer's platform more than they need. Its value proposition centers on governance, knowledge grounding, and multi-agent workflow automation across an organization, which adds setup and onboarding overhead that isn't justified if the actual use case is occasional drafting or editing by a handful of people.$q$, $q$Teams that need a genuinely multilingual product interface, native mobile apps, or a fully self-serve, credit-card checkout experience should also be cautious: Writer's own UI is English-only (content generation supports many languages, but menus and navigation are not localized), and larger deployments typically require talking to sales rather than an instant self-service signup.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the core of Writer's platform is the Palmyra family of proprietary large language models, including general-purpose and domain-specific variants (such as Palmyra Creative and Palmyra Vision) tuned for enterprise tone, tool-calling, and long-context tasks. Because Writer owns its models rather than reselling third-party APIs, it can offer tighter data-handling guarantees and domain fine-tuning as part of enterprise contracts.$q$, $q$The Knowledge Graph lets organizations connect internal documents, wikis, and business systems so agents and chat answers are grounded in company-specific data rather than generic web knowledge. On top of this sits WRITER Agent (a chat and automation interface), AI Studio for building and deploying custom agents, and Playbooks вЂ” no-code, multi-step automations that chain prompts, approvals, and connectors into repeatable workflows such as campaign briefs, claims summaries, or research reports.$q$, $q$Governance and brand-control tooling round out the feature set: configurable style guides and terminology enforcement, content safety and PII protection policies, role-based access control, observability and audit logging for agent activity, and enterprise-grade compliance (SOC 2 Type II, HIPAA BAA, SAML SSO, SCIM) needed to pass procurement review at large companies.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', $q$the-writer-experience$q$, $q$The Writer Experience$q$, 2, ARRAY[$q$Getting started with Writer typically begins with a 14-day free trial of the entry-level Starter plan, which includes the core agent chat, a small number of Playbooks, and limited Knowledge Graph storage. Moving beyond that tier вЂ” to unlimited seats, larger knowledge storage, domain-tuned models, and the full governance stack вЂ” generally requires an Enterprise contract negotiated directly with Writer's sales team, so pricing transparency and self-serve scaling are limited past the entry tier.$q$, $q$Day-to-day, users interact through a chat-style assistant alongside templates and Playbooks for structured workflows, plus browser and app integrations (such as Google Docs and Microsoft Word add-ins) so content generated in Writer can be edited in the tools teams already use. Admins configure the brand style guide, terminology rules, and data connectors centrally, so individual writers mostly work within guardrails set by the organization rather than configuring the platform themselves.$q$, $q$Overall, reviewers describe the experience as polished and enterprise-grade but heavier than lightweight AI writing tools вЂ” better suited to organizations investing in a long-term AI content and agent strategy than to someone who wants an instant, no-commitment writing aid. The tradeoff is added structure and compliance in exchange for a steeper onboarding curve and reliance on a sales-driven buying process for full functionality.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
