INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ca1d9da3-5f04-44f4-a493-8de2c1275125', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$AI Article Writer$q$, $q$Generates long-form, SEO-structured blog articles and outlines from a topic or keyword, drawing on web research to produce a full draft in minutes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Chatsonic$q$, $q$A conversational AI assistant that can be grounded in a site's own SEO and analytics data for more context-aware answers than a generic chatbot.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$AI search visibility tracking$q$, $q$Monitors how a brand is cited and represented across ChatGPT, Gemini, Google AI Overviews, and other AI platforms.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Site audits$q$, $q$Scans site pages for technical and structured-data issues that affect how both traditional and AI crawlers read and index content.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Action Center$q$, $q$Surfaces prioritized on-page and off-page fixes (available on higher-tier plans) aimed at improving AI and search visibility.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Content template library$q$, $q$Includes templates for ads, product descriptions, emails, social captions, and other short-form copy beyond long-form articles.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$SEO checker and optimizer$q$, $q$Analyzes drafts against target keywords and on-page SEO best practices before publishing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$WordPress integration$q$, $q$Publishes generated content directly to connected WordPress sites without manual copy-pasting.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Team collaboration$q$, $q$Supports multiple users and projects per workspace, with seat limits that scale by plan tier.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Plagiarism and AI-content checking$q$, $q$Flags originality issues in generated drafts before they are published.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Combines long-form AI article generation with SEO and AI-search-visibility tracking in one subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Article Writer can produce a full draft quickly, saving time on first drafts of SEO content$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Free trial with no credit card required lets new users test core tools before paying$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Broad template library covers many short-form content types beyond blog articles$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Actively expanding into generative engine optimization (GEO), a newer capability many competitors lack$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$No permanent free plan; paid tiers start around $79/month and rise quickly for team seats and higher usage limits$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$AI-generated drafts often need meaningful human editing for voice, accuracy, and depth$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Recent pivot toward AI-search-visibility tracking has added complexity for users who just want a simple writing tool$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Higher tiers required for multiple users, more projects, and full Action Center automation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Enterprise-level features (SSO/SAML, dedicated strategist, full platform coverage) are only available on custom-priced Enterprise plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$What is Writesonic used for?$q$, $q$Writesonic is used to generate long-form SEO articles and short-form marketing copy with AI, and to track and improve how a brand is cited and represented across AI search platforms like ChatGPT and Gemini.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Does Writesonic have a free plan?$q$, $q$Writesonic does not offer a permanent free plan, but it provides a free, no-credit-card trial with a limited word and feature allowance so new users can test the Article Writer and Chatsonic before subscribing.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$How much does Writesonic cost?$q$, $q$Paid plans start at around $79 per month when billed annually for the Starter tier, rising to $199 for Basic and $399 for Growth, with a custom-priced Enterprise plan for larger organizations.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Is Writesonic only an AI writing tool?$q$, $q$No. While it still includes an AI Article Writer and the Chatsonic assistant, Writesonic has expanded into AI search visibility (GEO) tracking, site audits, and automated content and technical fixes aimed at improving AI search rankings.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Can Writesonic content be published directly to a website?$q$, $q$Yes, Writesonic includes a WordPress integration that lets users publish generated articles directly to connected sites without manually copying content over.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Scaling SEO content production$q$, $q$Generate long-form, keyword-targeted blog drafts quickly, then edit and publish to grow organic search traffic.$q$, $q$Content marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Monitoring AI search visibility$q$, $q$Track how often and how favorably a brand is cited across ChatGPT, Gemini, and other AI assistants to spot visibility gaps.$q$, $q$SEO teams and digital agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Multi-channel marketing copy$q$, $q$Produce ad copy, product descriptions, and social captions from a single template library to support campaigns.$q$, $q$E-commerce and growth marketing teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Managing client visibility across brands$q$, $q$Track AI and search visibility for multiple client accounts and prioritize fixes through a shared action center.$q$, $q$Marketing and SEO agencies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Starter$q$, $q$$79/month$q$, $q$annual (monthly billing also available at a higher rate)$q$, $q$["Tracks 3 AI platforms (ChatGPT, Gemini, Google AI Overviews)","50 prompts tracked daily","15 AI articles per month","10 site audits (up to 100 pages each)","1 user, 1 project","Limited agentic workflow trial runs"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Basic$q$, $q$$199/month$q$, $q$annual (monthly billing also available at a higher rate)$q$, $q$["Tracks 3 AI platforms","100 prompts tracked daily","25 AI articles per month","20 site audits (up to 1,200 pages each)","2 users, 1 project","Limited agentic workflow trial runs"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Growth$q$, $q$$399/month$q$, $q$annual (monthly billing also available at a higher rate)$q$, $q$["200 prompts tracked daily plus sentiment analysis","50 AI articles per month","50 site audits (up to 2,500 pages each)","3 users, 2 projects","Action Center trial (limited on-page and off-page actions)"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$Enterprise$q$, $q$Custom$q$, $q$annual contract$q$, $q$["Tracks all 10 AI platforms","Custom prompt and region coverage","Full Action Center access and unlimited agentic workflows","Custom users and projects","Dedicated AI search strategist","SSO/SAML, SOC 2 Type II, HIPAA, GDPR compliance"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Writesonic launched in 2021 as an AI copywriting tool built on early GPT models, aimed at helping marketers generate blog posts, ads, and product descriptions faster than manual writing allowed. Over time it expanded into a fuller content suite, adding an SEO-focused long-form article writer, a conversational assistant called Chatsonic, and dozens of short-form templates for social media, email, and e-commerce copy.$q$, $q$More recently, Writesonic has repositioned itself as an AI search visibility platform, sometimes described as a generative engine optimization (GEO) tool. The current product tracks how brands are cited and represented across ChatGPT, Gemini, Google AI Overviews, and other AI assistants, then layers content generation and technical fixes on top of that monitoring to help close visibility gaps.$q$, $q$In practice, Writesonic today functions as a hybrid: it still houses the AI Article Writer and Chatsonic that made it popular as a writing tool, but its pricing, dashboard, and messaging now center on tracking prompts, citations, and AI-driven traffic, then shipping content and site fixes intended to improve how often a brand appears in AI-generated answers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$who-writesonic-is-for$q$, $q$Who Writesonic Is For$q$, 2, ARRAY[$q$Writesonic suits marketing teams and content operations that need to publish SEO-oriented long-form content at volume without hiring a large writing staff. The Article Writer's ability to draft a full-length blog post from a topic or keyword makes it useful for teams that already have an editorial process and simply need a faster first draft to edit and publish.$q$, $q$It also fits agencies and in-house SEO teams that want visibility into how their clients or brand appear inside AI chat answers, not just traditional search results. The platform's prompt tracking, citation monitoring, and site audit tools are built for people who already think in terms of keywords, rankings, and technical SEO and want an AI-search equivalent of that workflow.$q$, $q$E-commerce brands and growth-stage companies that need copy across many channels (ads, product pages, emails, social captions) alongside SEO content can use Writesonic as a single subscription instead of stitching together several point tools, since it bundles writing, on-page SEO checking, and AI visibility tracking under one login.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo bloggers, students, or hobbyists looking for a cheap or permanently free AI writing tool are likely to find Writesonic's current pricing steep; plans now start around $79 a month billed annually, and the entry tier is scoped around AI-visibility tracking rather than unlimited casual writing, with only a limited, credit-based trial available before payment.$q$, $q$Writers and editors who need nuanced, highly stylized, or deeply researched long-form writing may find the output requires substantial editing, as is common with AI-generated drafts. Teams that prioritize a distinctive brand voice or investigative depth over speed may prefer a more manual workflow or a tool built specifically around fine-grained style control.$q$, $q$Small teams that only want a straightforward content generator, without needing AI search-visibility tracking, prompt monitoring, or site audits, may find Writesonic's current feature set and pricing structure more complex and more expensive than dedicated, simpler AI writing tools that focus purely on drafting.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the core of Writesonic is the AI Article Writer, which generates long-form, SEO-structured articles by pulling from web research and real-time data, alongside Chatsonic, a chat-style assistant that can be grounded in a site's own SEO and analytics data rather than acting as a generic chatbot.$q$, $q$Layered on top is an AI search visibility module that tracks how a brand's prompts and citations appear across multiple AI platforms, paired with technical site audits that flag crawlability and structured-data issues affecting how AI crawlers read a site. An 'action center' in higher tiers can queue up on-page and off-page fixes based on those findings.$q$, $q$Supporting tools include a template library covering dozens of content types (ads, product descriptions, emails, social posts), a plagiarism and AI-content checker, WordPress publishing integration, and team collaboration features such as multiple seats and projects on higher-tier plans.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f31dc073-4cc3-41a0-aee3-8701aed38b64', $q$the-writesonic-experience$q$, $q$The Writesonic Experience$q$, 2, ARRAY[$q$New users typically start with a free, no-credit-card trial that provides a limited word or credit allowance to test the Article Writer and Chatsonic before committing to a paid plan. The onboarding flow asks for basic brand and topic information so the tool can tailor tone and keyword targeting for generated drafts.$q$, $q$The interface is organized around a dashboard that separates content generation tools from the newer AI-visibility tracking and site-audit sections, which means users coming from the classic 'AI writing tool' era of Writesonic will notice the product now surfaces prompt and citation data as prominently as the writing editor itself.$q$, $q$Overall satisfaction tends to hinge on expectations: users who came for fast SEO drafts and simple ad copy generally report a smooth, template-driven experience, while users evaluating the newer AI-search-tracking features describe more of a learning curve, since it introduces GEO-specific concepts like prompt volume and citation share that go beyond traditional content generation.$q$]::text[], 4);
